def split_opts(text):
    """拆分选项，处理 A．2B．3C．4D．5 这种连续格式"""
    text = text.replace('\xa0', '').replace('\x00', '')
    parts = re.split(r'(?=[A-D][．\.])', text)
    result = [p.strip() for p in parts if p.strip()]
    # 保留空选项但标记（如 "A．" 显示为 "A．____"）
    final = []
    for p in result:
        if re.match(r'^[A-D]．\s*$', p):
            final.append(p.replace('．', '．____'))  # 空选项用下划线占位
        else:
            final.append(p)
    return final

