python3 -c "
import urllib.request, json, re

url = 'https://www.youtube.com/watch?v=j262kCYZxZI'
req = urllib.request.Request(url, headers={
    'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/120.0.0.0',
    'Accept-Language': 'en-US,en;q=0.9,zh-CN;q=0.8'
})
r = urllib.request.urlopen(req, timeout=15)
html = r.read().decode('utf-8', errors='ignore')

# 提取ytInitialData中的视频信息
data_m = re.search(r'ytInitialData\s*=\s*(\{.*?\});\s*</script>', html)
if data_m:
    d = json.loads(data_m.group(1))
    # 找videoPrimaryInfoRenderer
    def search(obj, target_keys, path='', depth=0):
        if depth > 12: return
        results = []
        if isinstance(obj, dict):
            for k, v in obj.items():
                if k in target_keys and v:
                    results.append((path+'.'+k, str(v)[:300]))
                results.extend(search(v, target_keys, path+'.'+k, depth+1))
        elif isinstance(obj, list):
            for i, item in enumerate(obj[:30]):
                results.extend(search(item, target_keys, path+f'[{i}]', depth+1))
        return results

    targets = ['title','viewCount','shortDescription','publishedTimeText','ownerText','lengthText']
    results = search(d, targets)
    seen = set()
    for path, val in results:
        key = val[:50]
        if key not in seen:
            seen.add(key)
            print(f'{path}: {val}')
" 2>&1

